package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import java.lang.foreign.MemorySegment;

import org.apache.datasketches.common.SketchesArgumentException;

/** Heap compact OmniSketch. */
final class HeapCompactOmniSketch extends CompactOmniSketch {
	private final int lgWidth;
	private final int numRows;
	private final int nominalEntries;
	private final long seed;
	private final long totalUpdates;
	private final int retainedEntries;
	private final OmniSketchCell[][] cells;

	HeapCompactOmniSketch(final int lgWidth, final int numRows, final int nominalEntries, final long seed,
			final long totalUpdates, final int retainedEntries, final OmniSketchCell[][] cells) {
		this.lgWidth = lgWidth;
		this.numRows = numRows;
		this.nominalEntries = nominalEntries;
		this.seed = seed;
		this.totalUpdates = totalUpdates;
		this.retainedEntries = retainedEntries;
		this.cells = cells;
	}

	@Override
	public int getLgWidth() {
		return lgWidth;
	}

	@Override
	public int getNumRows() {
		return numRows;
	}

	@Override
	public int getNominalEntries() {
		return nominalEntries;
	}

	@Override
	public long getSeed() {
		return seed;
	}

	@Override
	public long getTotalUpdates() {
		return totalUpdates;
	}

	@Override
	public int getRetainedEntries() {
		return retainedEntries;
	}

	@Override
	public boolean isEmpty() {
		return totalUpdates == 0L;
	}

	@Override
	public OmniSketchEstimate estimate(final OmniSketchPredicate predicate) {
		return summary(predicate).asEstimate();
	}

	@Override
	public CompactOmniSketch compact(final MemorySegment dstSeg) {
		if (dstSeg == null) {
			return this;
		}
		final int bytes = getCompactBytes();
		if (dstSeg.byteSize() < bytes) {
			throw new SketchesArgumentException("Destination MemorySegment is too small for compact OmniSketch: "
					+ dstSeg.byteSize() + " < " + bytes);
		}
		OmniSketchSerializationUtil.writeSketch(this, dstSeg, true);
		return CompactOmniSketch.wrap(dstSeg.asSlice(0, bytes));
	}

	@Override
	public byte[] toByteArray() {
		return OmniSketchSerializationUtil.toByteArray(this);
	}

	@Override
	public int getCompactBytes() {
		return OmniSketchSerializationUtil.getSerializedSize(this);
	}

	@Override
	OmniSketchCell getCell(final int row, final int column) {
		return cells[row][column];
	}

	@Override
	public String toString() {
		return "HeapCompactOmniSketch{" + "lgWidth=" + lgWidth + ", numRows=" + numRows + ", nominalEntries="
				+ nominalEntries + ", totalUpdates=" + totalUpdates + ", retainedEntries=" + retainedEntries + '}';
	}
}
